Here is a simple 3D model of a house rendered using **HTML and JavaScript with Three.js**. This code creates a complete scene with a house, a ground plane, lighting, and shadows.

You can save the code below as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Building the House

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5C4033 }); // Dark wood

        const houseGroup = new THREE.Group();

        // --- The Base (Walls) ---
        // We build the walls using a box, but we need to remove the top face to put a roof on it.
        const wallGeometry = new THREE.BoxGeometry(10, 6, 8);
        const wall = new THREE.Mesh(wallGeometry, wallMaterial);
        wall.position.y = 3; // Half height
        wall.castShadow = true;
        wall.receiveShadow = true;
        houseGroup.add(wall);

        // --- The Roof (Pyramid) ---
        const roofGeometry = new THREE.ConeGeometry(9, 4, 4); // 4 segments for a pyramid
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 8; // Half height of wall + half height of roof
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // --- Windows ---
        function createWindow(x, z, y) {
            const winGeo = new THREE.BoxGeometry(2, 2, 0.2);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }

        // Front Windows
        createWindow(-2, 0, 3.5);
        createWindow(2, 0, 3.5);
        // Side Window
        createWindow(0, 0, -3.5);

        // --- The Door ---
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 4); // Centered on front face
        door.castShadow = true;
        houseGroup.add(door);

        // --- Chimney ---
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(4, 10, 0); // On the right side of the roof
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 7. Ground (Grass)
        const groundGeometry = new THREE.PlaneGeometry(100, 100);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 8. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

### Features included:
*   **3D Geometry:** A box for the walls, a cone for the roof, and smaller boxes for windows, a door, and a chimney.
*   **Lighting:** Ambient light for general visibility and a Directional Light (sun) that casts realistic shadows.
*   **Interactivity:** You can click and drag to rotate the camera, scroll to zoom, and right-click to pan.
*   **Materials:** Different colors for walls, roof, and windows.
